C0i[cc11, p_, 0, p_, m1_, m2_, m2_] :> (2 m1^2 (1 - 2 B0[p, m1, m1]) - m2 p B0[0, 0, m2])/(3 m2 p^2) + 1/(6 m2 p^2) (del - 2) (-m1 m2 B0[0, 0, m1] + m2 (m2 - 2 p) B0[0, 0, m2] - 4 m1^2 B0[p, m1, m1]) + 1/((m1 + m2 - p)^2 - 4 m1 m2) (1/(3 p) m1 (-2 m1 B0[0, 0, m1] + (m1 + m2 - p) B0[0, 0, m2] + 3 (m1 - m2 + p) B0[p, m1, m2]) + 1/(6 p^2) (del - 2) (-4 m1^2 p B0[0, 0, m1] + 2 m1 (m1 + m2 - p) p B0[0, 0, m2] + (m1 - m2 + p)^3 B0[p, m1, m2])),
