C0i[cc2, 0, p_, p_, m1_, m1_, m2_] :> 1/(p ((m1 + m2 - p)^2 - 4 m1 m2)) ((-1 + del) (m1 (m2 - m1 + p) B0[0, 0, m1] + m2 (m1 - m2 + p) B0[0, 0, m2]) + ((-1 + del) (m1 - m2)^2 + (m1 + m2) p - del p^2) B0[p, m1, m2]),
