C0i[cc00, 0, 0, 0, m_, m_, m_] :> 1/4 (1 - del) B0[0, 0, m],
C0i[cc00, 0, 0, 0, m1_, m1_, m2_] :> A0[m1]/(2 (m1 - m2)) + (m1 A0[m1] - m2 A0[m2])/(2 (del - 2) (m1 - m2)^2),
C0i[cc00, 0, 0, 0, m1_, m2_, m2_] :> -(A0[m2]/(2 (m1 - m2)) + (m1 A0[m1] - m2 A0[m2])/(2 (del - 2) (m1 - m2)^2)),
C0i[cc00, 0, p_, p_, m1_, m1_, m2_] :> 1/(4 p) (B0[0, 0, m1] m1 - B0[0, 0, m2] m2 + B0[p, m1, m2] (p - m1 + m2)),(*CHECK*)
C0i[cc00, p_, 0, p_, m2_, m1_, m1_] :> C0i[cc00, 0, p, p, m1, m1, m2],
C0i[cc0, 0, 0, 0, m_, m_, m_] :> -del/(2 m) B0[0, m, m],
C0i[cc0, 0, 0, 0, m1_, m1_, m2_]|C0i[cc0, 0, 0, 0, m1_, m2_, m1_]|C0i[cc0, 0, 0, 0, m2_, m1_, m1_] :> 1/(m1 - m2) (1 - del) B0[0, 0, m1] - m1/(m1 - m2)^2 B0[0, 0, m1] + m2/(m1 - m2)^2 B0[0, 0, m2],
C0i[cc0, 0, 0, 0, m1_, m2_, m3_] :> -m1/(m1 - m2)/(m3 - m1) B0[0, 0, m1] - m2/(m2 - m3)/(m1 - m2) B0[0, 0, m2] - m3/(m3 - m1)/(m2 - m3) B0[0, 0, m3],
C0i[cc0, 0, p_, p_, m1_, m1_, m2_] :> 1/((m1 + m2 - p)^2 - 4 m1 m2) ((-1 + del) (m1 + m2 - p) B0[0, 0, m1] - 2 (-1 + del) m2 B0[0, 0, m2] + (-1 + 2 del) (m2 - m1 + p) B0[p, m1, m2]),
C0i[cc0, p_, 0, p_, m2_, m1_, m1_] :> C0i[cc0, 0, p, p, m1, m1, m2]
